  const seen = new Set();
  return items.filter((chat) => {
    const key = chat?.id || chat?.chatId || `${chat?.title || ""}-${chat?.createdAt || chat?.updatedAt || ""}`;
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

function App() {


