  transition: .22s ease;
  pointer-events: auto !important
}

.light .source-card-v2,
.light .source-card {
  background: linear-gradient(180deg, rgba(255, 255, 255, .94), rgba(255, 255, 255, .70)), rgba(255, 255, 255, .72);
  box-shadow: 0 16px 42px rgba(15, 23, 42, .12)
}

.source-card-v2:hover,
.source-card:hover {
  transform: translateY(-3px);
  border-color: rgba(34, 211, 238, .45);
  box-shadow: 0 22px 55px rgba(0, 0, 0, .24), 0 0 0 1px rgba(34, 211, 238, .12)
}

.source-domain,
.source-card-top {
  width: fit-content;
  max-width: 100%;
  font-size: 12px;
  color: #67e8f9;
  background: rgba(34, 211, 238, .10);
  border: 1px solid rgba(34, 211, 238, .18);
  border-radius: 999px;
  padding: 5px 9px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis
}

.source-card-v2 strong,
.source-card strong {
  font-size: 14px;
  line-height: 1.35;
  color: var(--text);
  display: block
}

.source-card-v2 p,
.source-card p {
  margin: 0;
  color: var(--muted);
  font-size: 12.5px;
  line-height: 1.5;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
  flex: 1
}

/* Composer */
.input-area {
  flex: 0 0 auto;
  min-height: 92px;
  padding: 10px 18px 18px;
  background: linear-gradient(to top, rgba(5, 11, 24, .98), rgba(5, 11, 24, .72), transparent);
  z-index: 30
}

.light .input-area {
  background: linear-gradient(to top, rgba(247, 249, 255, .98), rgba(247, 249, 255, .78), transparent)
}

.chat-input-box {
  position: relative;
  width: min(980px, calc(100% - 20px));
  min-height: 72px;
  margin: 0 auto;
  border-radius: 32px;
  border: 1px solid rgba(124, 60, 255, .45);
  background: var(--input);
  backdrop-filter: blur(28px);
  -webkit-backdrop-filter: blur(28px);
  display: grid;
  grid-template-columns: 48px minmax(0, 1fr)48px 48px;
  grid-template-rows: auto 48px;
  align-items: center;
  gap: 10px;
  padding: 10px;
  overflow: visible;
  box-shadow: 0 18px 55px rgba(0, 0, 0, .30), inset 0 1px 0 rgba(255, 255, 255, .09)
}

.chat-input-box:after {
  content: "";
  position: absolute;
  inset: 0;
  border-radius: inherit;
  padding: 2px;
  background: conic-gradient(from var(--inputGlow), transparent 0deg, transparent 60deg, #7c3cff 120deg, #22d3ee 185deg, #a855f7 250deg, transparent 315deg, transparent 360deg);
  -webkit-mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
  animation: inputRun 2.2s linear infinite;
  opacity: .78
}

@keyframes inputRun {
  to {
    --inputGlow: 360deg
  }
}

.composer-attachments-list {
  grid-column: 1/-1;
  grid-row: 1;
  width: 100%;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  padding: 0 4px 4px;
  position: relative;
  z-index: 3
}

.composer-attachment-card {
  max-width: min(260px, 100%);
  min-height: 38px;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 7px 9px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--glass);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px)
}

.composer-attachment-name {
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
  font-size: 12px;
  color: var(--text)
}

.composer-attachment-remove,
.remove-file {
  width: 22px !important;
  height: 22px !important;
  min-width: 22px !important;
  border-radius: 999px !important;
  display: grid !important;
  place-items: center !important;
  padding: 0 !important;
  border: 0 !important;
  background: rgba(239, 68, 68, .18) !important;
  color: #fecaca !important;
  transform: none !important
}

.file-preview,
.input-area>.file-preview {
  display: none !important
}

.chat-input-box textarea {
  grid-column: 2;
  grid-row: 2;
  align-self: center;
  width: 100%;
  min-height: 48px;
  height: 48px;
  max-height: 160px;
  resize: none;
  border: 0;
  outline: 0;
  background: transparent;
  color: var(--text);
  font-size: 15px;
  font-weight: 400;
  padding: 12px 8px;
  line-height: 24px;
  overflow-y: auto;
  position: relative;
  z-index: 2
}

.chat-input-box textarea::placeholder {
  color: var(--muted);
  opacity: .72
}

.upload-btn,
.voice-btn,
.send-circle-btn {
  position: relative;
  z-index: 2;
  width: 48px !important;
  height: 48px !important;
  min-width: 48px !important;
  border-radius: 999px;
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  padding: 0 !important;
  align-self: center;
  justify-self: center
}

.upload-btn {
  grid-column: 1;
  grid-row: 2;
  font-size: 0 !important
}

.upload-btn:before {
  content: "+" !important;
  font-size: 31px !important;
  line-height: 1 !important;
  font-weight: 520 !important;
  color: var(--text)
}

.voice-btn {
  grid-column: 3;
  grid-row: 2
}

.send-circle-btn {
  grid-column: 4;
  grid-row: 2;
  border: 0 !important;
  background: linear-gradient(135deg, #8b5cf6, #7c3cff) !important;
  color: #fff !important;
  font-size: 22px;
  box-shadow: 0 8px 22px rgba(124, 60, 255, .36) !important
}

.send-circle-btn svg {
  width: 23px !important;
  height: 23px !important
}

.stop-speech-btn {
  grid-column: 2/-1;
  grid-row: 1;
  justify-self: start;
  min-height: 36px !important;
  border-radius: 999px !important;
  padding: 0 12px !important;
  color: var(--text) !important;
  background: var(--glass2) !important
}

/* Work panel */
.work-panel {
  height: calc(100vh - 28px);
  margin: 14px 14px 14px 0;
  border-radius: 24px;
  border: 1px solid var(--line);
  background: linear-gradient(180deg, rgba(255, 255, 255, .08), rgba(255, 255, 255, .035)), var(--panel);
  backdrop-filter: blur(28px);
  -webkit-backdrop-filter: blur(28px);
  box-shadow: 0 28px 90px var(--shadow);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  z-index: 5
}

.panel-header {
  flex: 0 0 auto;
  min-height: 88px;
  padding: 14px 16px;
  border-bottom: 1px solid var(--line);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
