function cleanSnippet(text = "") {
  return String(text)
    .replace(/<[^>]*>/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function shouldUseWikipedia(query = "") {
  const q = query.toLowerCase();

  return (
    q.includes("who is") ||
    q.includes("what is") ||
